final_template:
AWSTemplateFormatVersion: '2010-09-09'
Description: CloudFormation template to create a CloudWatch Dashboard and Log Group for AWS Client VPN usage monitoring.

Parameters:
  EnvironmentName:
    Type: String
    Default: prod
    Description: Environment label used in resource naming and dashboard title (e.g., prod, staging).

Resources:
  ClientVpnLogGroup:
    Type: AWS::Logs::LogGroup
    DeletionPolicy: Retain
    UpdateReplacePolicy: Retain
    Properties:
      LogGroupName: !Sub '/aws/client-vpn/${EnvironmentName}-endpoint'
      RetentionInDays: 731

  ClientVPNDashboard:
    Type: AWS::CloudWatch::Dashboard
    Properties:
      DashboardName: !Sub 'ClientVPNDashboard-${EnvironmentName}'
      DashboardBody:
        Fn::Sub:
          - |-
            {
              "widgets": [
                {
                  "type": "text",
                  "height": 2,
                  "width": 24,
                  "properties": {
                    "markdown": "# Endpoints Summary\nOverview of Client VPN endpoints, total connections, and unique users."
                  }
                },
                {
                  "type": "log",
                  "height": 8,
                  "width": 24,
                  "properties": {
                    "region": "${AWS::Region}",
                    "title": "Endpoints Summary",
                    "logGroupNames": ["${ClientVpnLogGroup}"],
                    "view": "table",
                    "query": "fields connection-id, common-name, client-vpn-endpoint-id | stats count(connection-id) as total_connections, count_distinct(common-name) as unique_users by client-vpn-endpoint-id | sort total_connections desc"
                  }
                },
                {
                  "type": "text",
                  "height": 2,
                  "width": 24,
                  "properties": {
                    "markdown": "# Connection Durations\nAverage, maximum, and minimum connection durations per endpoint."
                  }
                },
                {
                  "type": "log",
                  "height": 8,
                  "width": 24,
                  "properties": {
                    "region": "${AWS::Region}",
                    "title": "Connection Durations",
                    "logGroupNames": ["${ClientVpnLogGroup}"],
                    "view": "table",
                    "query": "fields connection-start-time, connection-end-time | filter connection-end-time > 0 | stats avg(connection-end-time - connection-start-time) as avg_duration_seconds, max(connection-end-time - connection-start-time) as max_duration, min(connection-end-time - connection-start-time) as min_duration by client-vpn-endpoint-id"
                  }
                },
                {
                  "type": "text",
                  "height": 2,
                  "width": 24,
                  "properties": {
                    "markdown": "# Data Transfer Volumes\nTotal and average ingress/egress bytes per endpoint."
                  }
                },
                {
                  "type": "log",
                  "height": 8,
                  "width": 24,
                  "properties": {
                    "region": "${AWS::Region}",
                    "title": "Data Transfer Volumes",
                    "logGroupNames": ["${ClientVpnLogGroup}"],
                    "view": "table",
                    "query": "fields ingress-bytes, egress-bytes | stats sum(ingress-bytes) as total_ingress, sum(egress-bytes) as total_egress, avg(ingress-bytes) as avg_ingress, avg(egress-bytes) as avg_egress by client-vpn-endpoint-id"
                  }
                },
                {
                  "type": "text",
                  "height": 2,
                  "width": 24,
                  "properties": {
                    "markdown": "# User Activity & Authentication Breakdown\nConnections and unique users per authentication type and endpoint."
                  }
                },
                {
                  "type": "log",
                  "height": 8,
                  "width": 24,
                  "properties": {
                    "region": "${AWS::Region}",
                    "title": "User Activity & Authentication Breakdown",
                    "logGroupNames": ["${ClientVpnLogGroup}"],
                    "view": "table",
                    "query": "fields authentication-type, common-name, connection-id | stats count(connection-id) as connections, count_distinct(common-name) as unique_users by authentication-type, client-vpn-endpoint-id | sort client-vpn-endpoint-id, authentication-type"
                  }
                }
              ]
            }
          - {ClientVpnLogGroup: !Ref ClientVpnLogGroup, EnvironmentName: !Ref EnvironmentName}
